def get_next_num(directory):
    existing = list(directory.glob("quiz_*_pt.json"))
    nums = []
    for f in existing:
        try: nums.append(int(f.stem.split("_")[1]))
        except: pass
    return max(nums) + 1 if nums else 1

def add_to_quiz(path, new_q):
    if not path.exists(): return False, 0
    data = json.loads(path.read_text(encoding="utf-8"))
    existing = data.get("questions",[])
    if len(existing) >= 50: return False, len(existing)
    next_num = len(existing) + 1
    for i,q in enumerate(new_q): q["num"] = next_num + i
    existing.extend(new_q)
    data["questions"] = existing[:50]
    path.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")
    return True, len(data["questions"])

